import React, { useEffect, useState } from "react";

const TENANT_API = process.env.REACT_APP_TENANT_API;
const ASSET_API = process.env.REACT_APP_ASSET_API;
const INCIDENT_API = process.env.REACT_APP_INCIDENT_API;

async function fetchJSON(url, options = {}) {
  const response = await fetch(url, options);

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`Error ${response.status}: ${text}`);
  }

  const contentType = response.headers.get("content-type");
  if (contentType && contentType.includes("application/json")) {
    return response.json();
  }

  const text = await response.text();
  throw new Error(`Expected JSON but received: ${text}`);
}

function App() {
  const [tenants, setTenants] = useState([]);
  const [selectedTenant, setSelectedTenant] = useState(
    localStorage.getItem("tenantId") || ""
  );

  const [tenantName, setTenantName] = useState("");
  const [adminEmail, setAdminEmail] = useState("");

  const [assets, setAssets] = useState([]);
  const [incidents, setIncidents] = useState([]);

  const [assetName, setAssetName] = useState("");
  const [assetType, setAssetType] = useState("");

  const [incidentTitle, setIncidentTitle] = useState("");
  const [incidentAssetId, setIncidentAssetId] = useState("");
  const [severity, setSeverity] = useState("Low");

  const [error, setError] = useState("");

  useEffect(() => {
    loadTenants();
  }, []);

  useEffect(() => {
    if (selectedTenant) {
      localStorage.setItem("tenantId", selectedTenant);
      loadDashboard(selectedTenant);
    } else {
      setAssets([]);
      setIncidents([]);
    }
  }, [selectedTenant]);

  const loadTenants = async () => {
    try {
      const data = await fetchJSON(TENANT_API);
      setTenants(data);

      const storedTenant = localStorage.getItem("tenantId");
      if (storedTenant && data.some((t) => t.tenantId === storedTenant)) {
        setSelectedTenant(storedTenant);
      } else if (data.length > 0) {
        setSelectedTenant(data[0].tenantId);
      } else {
        setSelectedTenant("");
      }

      setError("");
    } catch (err) {
      console.error("Error loading tenants:", err);
      setError("Failed to load tenants.");
    }
  };

  const loadDashboard = async (tenantId) => {
    try {
      const headers = { "X-Tenant-ID": tenantId };

      const assetsData = await fetchJSON(ASSET_API, { headers });
      const incidentsData = await fetchJSON(INCIDENT_API, { headers });

      setAssets(Array.isArray(assetsData) ? assetsData : []);
      setIncidents(Array.isArray(incidentsData) ? incidentsData : []);
      setError("");
    } catch (err) {
      console.error("Error loading dashboard:", err);
      setError(`Failed to load dashboard data: ${err.message}`);
    }
  };

  const createTenant = async (e) => {
    e.preventDefault();
    try {
      setError("");

      const created = await fetchJSON(TENANT_API, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: tenantName, adminEmail }),
      });

      setTenantName("");
      setAdminEmail("");

      await loadTenants();
      setSelectedTenant(created.tenantId);
    } catch (err) {
      console.error("Error creating tenant:", err);
      setError("Failed to create tenant.");
    }
  };

  const editTenant = async () => {
    if (!selectedTenant) {
      setError("Please select a tenant first.");
      return;
    }

    const tenant = tenants.find((t) => t.tenantId === selectedTenant);
    if (!tenant) return;

    const newName = prompt("Enter new tenant name", tenant.name);
    if (newName === null) return;

    const newEmail = prompt("Enter new admin email", tenant.adminEmail);
    if (newEmail === null) return;

    try {
      setError("");

      await fetchJSON(`${TENANT_API}/${selectedTenant}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: newName.trim() || tenant.name,
          adminEmail: newEmail.trim() || tenant.adminEmail,
        }),
      });

      await loadTenants();
    } catch (err) {
      console.error("Error editing tenant:", err);
      setError("Failed to edit tenant.");
    }
  };

  const deleteTenant = async () => {
    if (!selectedTenant) {
      setError("Please select a tenant first.");
      return;
    }

    const tenant = tenants.find((t) => t.tenantId === selectedTenant);
    if (!tenant) return;

    const confirmed = window.confirm(
      `Delete tenant "${tenant.name}" and all its assets/incidents?`
    );
    if (!confirmed) return;

    try {
      setError("");

      await fetchJSON(`${TENANT_API}/${selectedTenant}`, {
        method: "DELETE",
      });

      localStorage.removeItem("tenantId");
      await loadTenants();
    } catch (err) {
      console.error("Error deleting tenant:", err);
      setError("Failed to delete tenant.");
    }
  };

  const createAsset = async (e) => {
    e.preventDefault();

    if (!selectedTenant) {
      setError("Please select a tenant first.");
      return;
    }

    try {
      setError("");

      await fetchJSON(ASSET_API, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-Tenant-ID": selectedTenant,
        },
        body: JSON.stringify({
          name: assetName,
          type: assetType,
        }),
      });

      setAssetName("");
      setAssetType("");
      await loadDashboard(selectedTenant);
    } catch (err) {
      console.error("Error creating asset:", err);
      setError("Failed to create asset.");
    }
  };

  const editAsset = async (asset) => {
    const newName = prompt("Enter new asset name", asset.name);
    if (newName === null) return;

    const newType = prompt(
      "Enter new asset type (VM / DB / SWITCH)",
      asset.type
    );
    if (newType === null) return;

    try {
      setError("");

      await fetchJSON(`${ASSET_API}/${asset.id}`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          "X-Tenant-ID": selectedTenant,
        },
        body: JSON.stringify({
          name: newName.trim() || asset.name,
          type: (newType.trim() || asset.type).toUpperCase(),
        }),
      });

      await loadDashboard(selectedTenant);
    } catch (err) {
      console.error("Error editing asset:", err);
      setError("Failed to edit asset.");
    }
  };

  const deleteAsset = async (assetId) => {
    const confirmed = window.confirm("Delete this asset?");
    if (!confirmed) return;

    try {
      setError("");

      await fetchJSON(`${ASSET_API}/${assetId}`, {
        method: "DELETE",
        headers: {
          "X-Tenant-ID": selectedTenant,
        },
      });

      if (incidentAssetId === assetId) {
        setIncidentAssetId("");
      }

      await loadDashboard(selectedTenant);
    } catch (err) {
      console.error("Error deleting asset:", err);
      setError("Failed to delete asset.");
    }
  };

  const createIncident = async (e) => {
    e.preventDefault();

    if (!selectedTenant) {
      setError("Please select a tenant first.");
      return;
    }

    try {
      setError("");

      await fetchJSON(INCIDENT_API, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-Tenant-ID": selectedTenant,
        },
        body: JSON.stringify({
          title: incidentTitle,
          assetId: incidentAssetId,
          severity,
        }),
      });

      setIncidentTitle("");
      setIncidentAssetId("");
      setSeverity("Low");

      await loadDashboard(selectedTenant);
    } catch (err) {
      console.error("Error creating incident:", err);
      setError("Failed to create incident.");
    }
  };

  const editIncident = async (incident) => {
    const newTitle = prompt("Enter new incident title", incident.title);
    if (newTitle === null) return;

    const newSeverity = prompt(
      "Enter new severity (Low / Medium / High)",
      incident.severity
    );
    if (newSeverity === null) return;

    try {
      setError("");

      await fetchJSON(`${INCIDENT_API}/${incident.id}`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          "X-Tenant-ID": selectedTenant,
        },
        body: JSON.stringify({
          title: newTitle.trim() || incident.title,
          severity: newSeverity.trim() || incident.severity,
        }),
      });

      await loadDashboard(selectedTenant);
    } catch (err) {
      console.error("Error editing incident:", err);
      setError("Failed to edit incident.");
    }
  };

  const deleteIncident = async (incidentId) => {
    const confirmed = window.confirm("Delete this incident?");
    if (!confirmed) return;

    try {
      setError("");

      await fetchJSON(`${INCIDENT_API}/${incidentId}`, {
        method: "DELETE",
        headers: {
          "X-Tenant-ID": selectedTenant,
        },
      });

      await loadDashboard(selectedTenant);
    } catch (err) {
      console.error("Error deleting incident:", err);
      setError("Failed to delete incident.");
    }
  };

  return (
    <div>
      <header className="header">
        <h2>🏢 Multi-Tenant ITOM Dashboard</h2>

        <div style={{ display: "flex", gap: "10px", alignItems: "center" }}>
          <label>Select Tenant: </label>
          <select
            value={selectedTenant}
            onChange={(e) => setSelectedTenant(e.target.value)}
          >
            <option value="">Select Tenant</option>
            {tenants.map((tenant) => (
              <option key={tenant.tenantId} value={tenant.tenantId}>
                {tenant.name}
              </option>
            ))}
          </select>

          <button onClick={editTenant}>Edit Tenant</button>
          <button onClick={deleteTenant}>Delete Tenant</button>
        </div>
      </header>

      <div className="container">
        {error && (
          <div
            style={{
              backgroundColor: "#ffe6e6",
              color: "#cc0000",
              padding: "10px",
              marginBottom: "15px",
              borderRadius: "5px",
            }}
          >
            {error}
          </div>
        )}

        <div className="form-card">
          <h3>Onboard New Tenant</h3>
          <form onSubmit={createTenant}>
            <input
              type="text"
              placeholder="Tenant Name"
              value={tenantName}
              onChange={(e) => setTenantName(e.target.value)}
              required
            />
            <input
              type="email"
              placeholder="Admin Email"
              value={adminEmail}
              onChange={(e) => setAdminEmail(e.target.value)}
              required
            />
            <button type="submit">Create Tenant</button>
          </form>
        </div>

        <div className="cards">
          <div className="card">
            <h3>Total Assets</h3>
            <p className="count">{assets.length}</p>
          </div>
          <div className="card">
            <h3>Total Incidents</h3>
            <p className="count">{incidents.length}</p>
          </div>
        </div>

        <div className="form-card">
          <h3>Add Asset</h3>
          <form onSubmit={createAsset}>
            <input
              type="text"
              placeholder="Asset Name"
              value={assetName}
              onChange={(e) => setAssetName(e.target.value)}
              required
            />

            <select
              value={assetType}
              onChange={(e) => setAssetType(e.target.value)}
              required
            >
              <option value="">Select Asset Type</option>
              <option value="VM">VM</option>
              <option value="DB">DB</option>
              <option value="SWITCH">SWITCH</option>
            </select>

            <button type="submit">Create Asset</button>
          </form>
        </div>

        <div className="form-card">
          <h3>Report Incident</h3>
          <form onSubmit={createIncident}>
            <input
              type="text"
              placeholder="Incident Title"
              value={incidentTitle}
              onChange={(e) => setIncidentTitle(e.target.value)}
              required
            />

            <select
              value={incidentAssetId}
              onChange={(e) => setIncidentAssetId(e.target.value)}
              required
            >
              <option value="">Select Related Asset</option>
              {assets.map((asset) => (
                <option key={asset.id} value={asset.id}>
                  {asset.name} ({asset.type})
                </option>
              ))}
            </select>

            <select
              value={severity}
              onChange={(e) => setSeverity(e.target.value)}
            >
              <option value="Low">Low</option>
              <option value="Medium">Medium</option>
              <option value="High">High</option>
            </select>

            <button type="submit">Create Incident</button>
          </form>
        </div>

        <div className="lists">
          <div className="list">
            <h3>Recent Assets</h3>
            <ul>
              {assets.slice().reverse().map((asset) => (
                <li key={asset.id}>
                  <div>
                    {asset.name} ({asset.type})
                  </div>
                  <div style={{ marginTop: "6px" }}>
                    <button onClick={() => editAsset(asset)}>Edit</button>
                    <button
                      onClick={() => deleteAsset(asset.id)}
                      style={{ marginLeft: "8px" }}
                    >
                      Delete
                    </button>
                  </div>
                </li>
              ))}
            </ul>
          </div>

          <div className="list">
            <h3>Recent Incidents</h3>
            <ul>
              {incidents.slice().reverse().map((incident) => (
                <li key={incident.id}>
                  <div>
                    {incident.title} - {incident.severity}
                  </div>
                  <div style={{ marginTop: "6px" }}>
                    <button onClick={() => editIncident(incident)}>Edit</button>
                    <button
                      onClick={() => deleteIncident(incident.id)}
                      style={{ marginLeft: "8px" }}
                    >
                      Delete
                    </button>
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
